VAR _filter_lt= TREATAS(VALUES( dim_Admin_LT_OS[USER_ACCESS_ID] ), 'fact_Employee_List'[USER_ACCESS_ID])
VAR _admin = 
CALCULATE(
    DIVIDE(
        SUM('fact_Vacancy'[CLOSE_VACANCY_COUNT]),
        SUM('fact_Vacancy'[TOTAL_VACANCY]),
        BLANK())
)

VAR _admin_lt = 
CALCULATE(
    DIVIDE(
        SUM('fact_Vacancy'[CLOSE_VACANCY_COUNT]),
        SUM('fact_Vacancy'[TOTAL_VACANCY]),
        BLANK()),
    _filter_lt
)
VAR _res = 
    SWITCH(
        SELECTEDVALUE('t_HierarchyTypes'[Index]),
        0, _admin_lt,
        1, _admin
    )

RETURN 
TRIM(
    FORMAT(
        COALESCE(_res, "-"), 
        "##%"))
